    12→        switch self {
    13→        case .shy: return 1.5...3.0
    14→        case .curious: return 3.0...6.0
    15→        case .mischievous: return 2.0...5.0
    16→        case .chaotic: return 0.5...8.0
    17→        }
    18→    }
    19→
    20→    /// Retreat speed multiplier (1.0 = normal)
